// GameServer maintains the set of active clients, broadcasts messages,
// and manages admin commands.
type GameServer struct {
	clients    map[string]*Client // Registered clients, keyed by ID.
	broadcast  chan []byte        // Inbound messages from clients to be broadcast.
	register   chan *Client       // Register requests from clients.
	unregister chan *Client       // Unregister requests from clients.
	commands   map[string]Command // Registered admin commands.
	mu         sync.RWMutex       // Mutex for clients map and other shared resources.
}

// NewGameServer creates and returns a new GameServer instance.
func NewGameServer() *GameServer {
	return &GameServer{
		broadcast:  make(chan []byte),
		register:   make(chan *Client),
		unregister: make(chan *Client),
		clients:    make(map[string]*Client),
		commands:   make(map[string]Command),
	}
}

// RegisterCommand registers an admin command with its handler and required roles.
func (s *GameServer) RegisterCommand(name string, handler CommandHandlerFunc, requiredRoles []string, description string) {
	s.commands[name] = Command{
		Handler:       handler,
		RequiredRoles: requiredRoles,
		Description:   description,
	}
	log.Printf("Registered command: /%s (Required Roles: %v)", name, requiredRoles)
}

// Run starts the GameServer's event loop.
// This method should be run in a goroutine.
func (s *GameServer) Run() {
	for {
		select {
		case client := <-s.register:
			s.mu.Lock()
			s.clients[client.ID] = client
			s.mu.Unlock()
			log.Printf("Client registered: %s (Roles: %v)", client.ID, client.roles)
			client.SendMessage(ServerMessage{
				Type:    "server_message",
				Content: fmt.Sprintf("Welcome, %s! Your ID: %s. Your roles: %v", client.ID[:8], client.ID, client.roles),
			})
			s.BroadcastServerMessage(fmt.Sprintf("Client %s joined the game.", client.ID[:8]))

		case client := <-s.unregister:
			s.mu.Lock()
			if _, ok := s.clients[client.ID]; ok {
				delete(s.clients, client.ID)
				close(client.send) // Close client's send channel to stop writePump
				log.Printf("Client unregistered: %s", client.ID)
				s.BroadcastServerMessage(fmt.Sprintf("Client %s left the game.", client.ID[:8]))
			}
			s.mu.Unlock()

		case message := <-s.broadcast:
			s.mu.RLock()
			for _, client := range s.clients {
				select {
				case client.send <- message:
				default:
					// If a client's send channel is full, assume it's unresponsive
					// and unregister it.
					close(client.send)
					delete(s.clients, client.ID)
					log.Printf("Client %s send buffer full, unregistering", client.ID)
				}
			}
			s.mu.RUnlock()
		}
	}
}

// handleClientMessage processes a raw message received from a client.
func (s *GameServer) handleClientMessage(sender *Client, message []byte) {
	var clientMsg ClientMessage
	if err := json.Unmarshal(message, &clientMsg); err != nil {
		log.Printf("Error unmarshalling client message from %s: %v", sender.ID, err)
		sender.SendMessage(ServerMessage{
			Type:    "error",
			Content: "Invalid message format.",
		})
		return
	}

	switch clientMsg.Type {
	case "chat":
		s.handleChat(sender, clientMsg.Content)
	case "command":
		s.handleCommand(sender, clientMsg.Content)
	default:
		log.Printf("Unknown message type '%s' from client %s", clientMsg.Type, sender.ID)
		sender.SendMessage(ServerMessage{
			Type:    "error",
			Content: fmt.Sprintf("Unknown message type: %s", clientMsg.Type),
		})
	}
}

// handleChat processes a chat message and broadcasts it to all connected clients.
func (s *GameServer) handleChat(sender *Client, content string) {
	log.Printf("Chat from %s: %s", sender.ID[:8], content)
	serverMsg := ServerMessage{
		Type:     "chat",
		SenderID: sender.ID[:8], // Use truncated ID for chat for brevity
		Content:  content,
	}
	jsonMsg, err := json.Marshal(serverMsg)
	if err != nil {
		log.Printf("Error marshalling chat message: %v", err)
		return
	}
	s.broadcast <- jsonMsg
}

// handleCommand parses and executes an admin command.
func (s *GameServer) handleCommand(sender *Client, commandStr string) {
	log.Printf("Command from %s: %s", sender.ID[:8], commandStr)

	if !strings.HasPrefix(commandStr, "/") {
		sender.SendMessage(ServerMessage{
			Type:    "error",
			Content: "Commands must start with '/'.",
		})
		return
	}

	// Remove '/' and split the command string into parts
	parts := strings.Fields(commandStr[1:])
	if len(parts) == 0 {
		sender.SendMessage(ServerMessage{
			Type:    "error",
			Content: "Empty command.",
		})
		return
	}

	cmdName := strings.ToLower(parts[0]) // Command name (e.g., "kick")
	args := []string{}
	if len(parts) > 1 {
		args = parts[1:] // Arguments for the command
	}

	cmd, found := s.commands[cmdName]
	if !found {
		sender.SendMessage(ServerMessage{
			Type:    "error",
			Content: fmt.Sprintf("Unknown command: /%s. Type /help for a list of commands.", cmdName),
		})
		return
	}

	// Check if the sender has any of the required roles for this command
	if len(cmd.RequiredRoles) > 0 {
		hasRequiredRole := false
		for _, requiredRole := range cmd.RequiredRoles {
			if sender.HasRole(requiredRole) {
				hasRequiredRole = true
				break
			}
		}
		if !hasRequiredRole {
			sender.SendMessage(ServerMessage{
				Type:    "error",
				Content: fmt.Sprintf("Permission denied. You need one of these roles: %v", cmd.RequiredRoles),
			})
			return
		}
	}

	// Execute the command handler
	if err := cmd.Handler(sender, args); err != nil {
		sender.SendMessage(ServerMessage{
			Type:    "error",
			Content: fmt.Sprintf("Command /%s failed: %v", cmdName, err),
		})
		log.Printf("Command /%s from %s failed: %v", cmdName, sender.ID[:8], err)
	} else {
		// Handler functions typically send specific success messages,
		// but a generic one can be sent if the handler doesn't.
		// For this example, handlers send their own success messages.
		// sender.SendMessage(ServerMessage{
		// 	Type:    "server_message",
		// 	Content: fmt.Sprintf("Command /%s executed successfully.", cmdName),
		// })
		log.Printf("Command /%s from %s executed.", cmdName, sender.ID[:8])
	}
}

// BroadcastServerMessage sends a server-originated message to all connected clients.
