// --- Admin Command Handlers ---

// cmdKick kicks a specified player from the server.
func (s *GameServer) cmdKick(sender *Client, args []string) error {
	if len(args) < 1 {
		return fmt.Errorf("usage: /kick <player_id_prefix> [reason]")
	}
	targetIDPrefix := args[0]
	reason := "No reason provided."
	if len(args) > 1 {
		reason = strings.Join(args[1:], " ")
	}

	var targetClient *Client
	s.mu.RLock()
	for _, client := range s.clients {
		if strings.HasPrefix(client.ID, targetIDPrefix) {
			targetClient = client
			break
		}
	}
	s.mu.RUnlock()

	if targetClient == nil {
		return fmt.Errorf("player with ID prefix %s not found", targetIDPrefix)
	}

	if targetClient.ID == sender.ID {
		return fmt.Errorf("you cannot kick yourself")
	}

	// In a real system, you might add more sophisticated role hierarchy checks
	// to prevent lower-ranked admins from kicking higher-ranked ones.

	targetClient.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("You have been kicked by %s. Reason: %s", sender.ID[:8], reason),
	})
	s.BroadcastServerMessage(fmt.Sprintf("Player %s has been kicked by %s. Reason: %s", targetClient.ID[:8], sender.ID[:8], reason))
	targetClient.conn.Close() // Force disconnect
	sender.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("Successfully kicked %s.", targetClient.ID[:8]),
	})
	return nil
}

// cmdBan bans a specified player from the server. (Currently just kicks, for a real ban it would need a persistent list).
func (s *GameServer) cmdBan(sender *Client, args []string) error {
	if len(args) < 1 {
		return fmt.Errorf("usage: /ban <player_id_prefix> [reason]")
	}
	targetIDPrefix := args[0]
	reason := "No reason provided."
	if len(args) > 1 {
		reason = strings.Join(args[1:], " ")
	}

	var targetClient *Client
	s.mu.RLock()
	for _, client := range s.clients {
		if strings.HasPrefix(client.ID, targetIDPrefix) {
			targetClient = client
			break
		}
	}
	s.mu.RUnlock()

	if targetClient == nil {
		// Player not found online, but we can still "ban" them in a persistent store
		// For this example, we just log and acknowledge.
		s.BroadcastServerMessage(fmt.Sprintf("Player %s has been banned by %s. Reason: %s (Player was offline)", targetIDPrefix, sender.ID[:8], reason))
		log.Printf("Player %s banned by %s. Reason: %s", targetIDPrefix, sender.ID[:8], reason)
		sender.SendMessage(ServerMessage{
			Type:    "server_message",
			Content: fmt.Sprintf("Successfully banned player %s (may have been offline).", targetIDPrefix),
		})
		return nil
	}

	if targetClient.ID == sender.ID {
		return fmt.Errorf("you cannot ban yourself")
	}

	targetClient.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("You have been banned by %s. Reason: %s", sender.ID[:8], reason),
	})
	s.BroadcastServerMessage(fmt.Sprintf("Player %s has been banned by %s. Reason: %s", targetClient.ID[:8], sender.ID[:8], reason))
	targetClient.conn.Close() // Force disconnect
	log.Printf("Player %s banned by %s. Reason: %s", targetClient.ID[:8], sender.ID[:8], reason)
	sender.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("Successfully banned %s.", targetClient.ID[:8]),
	})
	return nil
}

// cmdGiveItems gives specified items to a player.
func (s *GameServer) cmdGiveItems(sender *Client, args []string) error {
	if len(args) < 2 {
		return fmt.Errorf("usage: /giveitems <player_id_prefix> <item_name> [amount]")
	}
	targetIDPrefix := args[0]
	itemName := args[1]
	amount := 1
	if len(args) > 2 {
		_, err := fmt.Sscanf(args[2], "%d", &amount)
		if err != nil || amount <= 0 {
			return fmt.Errorf("invalid amount, must be a positive number: %v", err)
		}
	}

	var targetClient *Client
	s.mu.RLock()
	for _, client := range s.clients {
		if strings.HasPrefix(client.ID, targetIDPrefix) {
			targetClient = client
			break
		}
	}
	s.mu.RUnlock()

	if targetClient == nil {
		return fmt.Errorf("player with ID prefix %s not found", targetIDPrefix)
	}

	// In a real game, this would interact with a game inventory system
	targetClient.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("You received %d x %s from %s!", amount, itemName, sender.ID[:8]),
	})
	s.BroadcastServerMessage(fmt.Sprintf("%s gave %d x %s to %s.", sender.ID[:8], amount, itemName, targetClient.ID[:8]))
	log.Printf("%s gave %d x %s to %s", sender.ID[:8], amount, itemName, targetClient.ID[:8])
	sender.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("Successfully gave %d x %s to %s.", amount, itemName, targetClient.ID[:8]),
	})
	return nil
}

// cmdListUsers lists all currently connected users.
func (s *GameServer) cmdListUsers(sender *Client, args []string) error {
	s.mu.RLock()
	defer s.mu.RUnlock()

	if len(s.clients) == 0 {
		sender.SendMessage(ServerMessage{Type: "server_message", Content: "No users currently connected."})
		return nil
	}

	var userList []string
	for _, client := range s.clients {
		userList = append(userList, fmt.Sprintf("%s (Roles: %v)", client.ID[:8], client.roles))
	}
	sender.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: fmt.Sprintf("Connected users: %s", strings.Join(userList, ", ")),
	})
	return nil
}

// cmdHelp displays available commands to the sender based on their roles.
func (s *GameServer) cmdHelp(sender *Client, args []string) error {
	var helpMessages []string
	helpMessages = append(helpMessages, "Available commands:")
	for name, cmd := range s.commands {
		// A command is shown if it has no role requirements OR the sender has at least one of the required roles.
		canExecute := false
		if len(cmd.RequiredRoles) == 0 {
			canExecute = true
		} else {
			for _, requiredRole := range cmd.RequiredRoles {
				if sender.HasRole(requiredRole) {
					canExecute = true
					break
				}
			}
		}

		if canExecute {
			roleInfo := ""
			if len(cmd.RequiredRoles) > 0 {
				roleInfo = fmt.Sprintf(" (Roles: %v)", cmd.RequiredRoles)
			}
			helpMessages = append(helpMessages, fmt.Sprintf("  /%s%s - %s", name, roleInfo, cmd.Description))
		}
	}
	sender.SendMessage(ServerMessage{
		Type:    "server_message",
		Content: strings.Join(helpMessages, "\n"),
	})
	return nil
}

// --- Main HTTP Handler for WebSocket Upgrade ---

// serveWs handles websocket requests from the peer.
func serveWs(server *GameServer, w http.ResponseWriter, r *http.Request) {
	// Extract roles from header. Clients might provide a comma-separated list.
	// NOTE: For browser-based WebSocket clients, custom headers cannot be set
	// directly with the standard `new WebSocket()` constructor.
	// To test role-based access using headers, use a tool like `wscat` (npm install -g wscat)
	// or Postman:
	// wscat -c ws://localhost:8080/ws --header "X-User-Roles: admin,developer"
	rawRoles := r.Header.Get(userRolesHeader)
	var roles []string
	if rawRoles != "" {
		roles = strings.Split(rawRoles, ",")
		for i := range roles {
			roles[i] = strings.TrimSpace(strings.ToLower(roles[i])) // Normalize roles to lowercase
		}
	} else {
		// Default role for clients who don't provide a header
		roles = []string{"player"}
	}

	conn, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Println("WebSocket upgrade error:", err)
		return
	}

	client := NewClient(server, conn, roles)
	server.register <- client // Register the new client with the game server

	// Start goroutines for reading and writing messages
	go client.writePump()
	go client.readPump()
}

func main() {
	gameServer := NewGameServer()

	// Register admin commands with their required roles and descriptions
	gameServer.RegisterCommand("kick", gameServer.cmdKick, []string{"admin", "moderator"}, "Kicks a player from the server. Usage: /kick <player_id_prefix> [reason]")
	gameServer.RegisterCommand("ban", gameServer.cmdBan, []string{"admin"}, "Bans a player from the server. Usage: /ban <player_id_prefix> [reason]")
	gameServer.RegisterCommand("giveitems", gameServer.cmdGiveItems, []string{"admin", "developer"}, "Gives items to a player. Usage: /giveitems <player_id_prefix> <item_name> [amount]")
	gameServer.RegisterCommand("listusers", gameServer.cmdListUsers, []string{"admin", "moderator", "player"}, "Lists all connected users.")
	gameServer.RegisterCommand("help", gameServer.cmdHelp, []string{}, "Shows available commands and their usage.") // No specific role required

	// Start the game server's main loop in a goroutine
	go gameServer.Run()

	// Set up HTTP route for WebSocket connections
	http.HandleFunc("/ws", func(w http.ResponseWriter, r *http.Request) {
		serveWs(gameServer, w, r)
	})

	log.Println("Game server started on :8080")
	log.Println("WebSocket endpoint: ws://localhost:8080/ws")
	log.Println(fmt.Sprintf("To connect with roles (e.g., as admin), use a client capable of setting custom headers (like wscat or Postman) and set the '%s' header.", userRolesHeader))
	log.Println(fmt.Sprintf("Example wscat command for admin: wscat -c ws://localhost:8080/ws --header \"%s: admin,developer\"", userRolesHeader))
	log.Println(fmt.Sprintf("Example wscat command for moderator: wscat -c ws://localhost:8080/ws --header \"%s: moderator\"", userRolesHeader))
	log.Println("Browser clients will connect with default 'player' role unless server-side logic assigns them differently.")

	// Start the HTTP server
	log.Fatal(http.ListenAndServe(":8080", nil))
}